type Policy = { items: Item[]; remainingCap: number };

export const runScenario = (scenario: unknown): unknown => {
  const { customer, steps } = scenario as Scenario;
  const policies: Record<number, Policy> = {};
  let priorQuoteCount = 0;
  const results = steps.map((step, index) => {
    if (step.op === "quote") {
      const premium = quotePremium(step.items, customer.yearsWithMHPCO, priorQuoteCount > 0);
      policies[index] = { items: step.items, remainingCap: 2 * insuranceSum(step.items) };
      priorQuoteCount += 1;
      return { premium };
    }
    const policy = policies[step.policy];
    let remainingCap = policy.remainingCap;
    let totalPayout = 0;
    for (const damage of step.incident.damages) {
      const desired = damage.amount - DEDUCTIBLE_G;
      const payout = Math.min(desired, remainingCap);
      totalPayout += payout;
      remainingCap -= payout;
    }
    policy.remainingCap = remainingCap;
    return { payout: totalPayout, remainingCap };
  });
  return { results };
};

